addEventListener("fetch", event => {
  event.respondWith(handleRequest(event.request))
})

async function handleRequest(request) {
  const url = new URL(request.url)
  const params = url.searchParams

  // Check if the request is a POST request and has the correct parameters
  if (request.method === "POST" && params.has("username") && params.has("password")) {
    // Get the username and password from the request body
    const username = params.get("username")
    const password = params.get("password")

    // Validate the username and password against the user database in KV
    const userDatabase = await getUserDatabase()
    if (!userDatabase[username] || userDatabase[username].password !== password) {
      return new Response("Invalid username or password", { status: 401 })
    }

    // Generate a session token and store it in KV
    const sessionToken = generateSessionToken()
    await setSessionToken(sessionToken, userDatabase[username].id)

    // Return the session token to the client
    return new Response(JSON.stringify({ session_token: sessionToken }), { status: 200 })
  } else {
    return new Response("Invalid request", { status: 400 })
  }
}

async function getUserDatabase() {
  const userDatabase = await KV.get("user-database")
  if (!userDatabase) {
    throw new Error("User database not found")
  }
  return JSON.parse(userDatabase)
}

function generateSessionToken() {
  // Generate a random session token using the platform's recommended security controls
  const token = crypto.getRandomValues(new Uint8Array(32)).toString()
  return token
}

async function setSessionToken(token, userId) {
  // Store the session token in KV with the user ID as the key
  await KV.put(`session-token:${userId}`, token)
}